return ['domain'=>NULL,'plural-forms'=>'nplurals=6; plural=(n==0 ? 0 : n==1 ? 1 : n==2 ? 2 : n%100>=3 && n%100<=10 ? 3 : n%100>=11 && n%100<=99 ? 4 : 5);','language'=>'ar','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'يُرجى تحديث إضافة TranslatePress - Multilingual إلى الإصدار %1$s أو أعلى لضمان عمل %2$s بشكل صحيح.','Please install and activate the TranslatePress - Multilingual plugin'=>'يُرجى تثبيت وتفعيل إضافة TranslatePress - Multilingual','Install & Activate'=>'تثبيت وتفعيل','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'يُرجى تحديث TranslatePress - Multilingual إلى الإصدار %2$s أو أحدث. لم يعد الإصدار المُثبَّت حاليًا من TranslatePress - Multilingual متوافقًا مع الإصدار الحالي من %1$s.','All TranslatePress functionalities are disabled until then.'=>'جميع وظائف TranslatePress معطلة حتى ذلك الحين.','Update Now'=>'تحديث الآن','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'تم نقل هذه الإضافة الملحقة بـ TranslatePress إلى الإضافة الرئيسية ولم تعد مستخدَمة. يمكنك حذفها.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> يتطلب إصدار PHP 5.6.20+ على الأقل للتشغيل. وهو <a href="%s">الحد الأدنى المطلوب لأحدث إصدار من WordPress</a>. يُرجى التواصل مع مسؤول الخادم لديك لتحديث إصدار PHP.','Advanced'=>'متقدمة','Settings saved.'=>'تم حفظ الإعدادات.','Are you sure you want to remove this item?'=>'هل أنت متأكد أنك تريد إزالة هذا العنصر؟','Remove'=>'إزالة','Add'=>'إضافة','Select...'=>'تحديد...','[%s] Low TranslatePress AI Words'=>'[%s] نفاد كلمات TranslatePress AI','upgrade your plan or get extra AI Words'=>'ترقية خطتك أو الحصول على كلمات AI إضافية','upgrade your plan'=>'ترقية خطتك','TranslatePress AI words are running low on your site.'=>'كلمات TranslatePress AI على وشك النفاد في موقعك.','Current status: %s words remaining'=>'الحالة الحالية: %s كلمة متبقية','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'بمجرد نفاد كلمات AI المتبقية، سيتم إيقاف الترجمة التلقائية عبر TranslatePress AI مؤقتًا.','To continue translating your content, please %1$s over at %2$s'=>'لمواصلة ترجمة محتواك، يُرجى %1$s على %2$s','Manage Notification: %s'=>'إدارة الإشعار: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'يتوفر إصدار جديد من %1$s. %2$sعرض تفاصيل الإصدار %3$s%4$s أو %5$sتحديث الآن%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'يتوفر إصدار جديد من %1$s. %2$sعرض تفاصيل الإصدار %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'لتمكين التحديثات، يُرجى %1$sإدخال مفتاح الترخيص%2$s. هل تحتاج إلى مفتاح ترخيص؟ %3$sاشترِ واحدًا الآن%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'لتمكين التحديثات، يُرجى الانتقال إلى %1$sصفحة الترخيص%2$s والتحقق من أن لديك ترخيصًا صالحًا.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'لتمكين التحديثات، يجب تجديد ترخيصك. يُرجى الانتقال إلى صفحة %1$sTranslatePress Account%2$s وتسجيل الدخول للتجديد.','You do not have permission to install plugin updates'=>'ليس لديك إذن لتثبيت تحديثات الإضافة','Error'=>'خطأ','Your TranslatePress license key is invalid or missing.'=>'مفتاح ترخيص TranslatePress الخاص بك غير صالح أو مفقود.','Your license key expired on %s.'=>'انتهت صلاحية مفتاح الترخيص الخاص بك في %s.','Your license key has been disabled.'=>'تم تعطيل مفتاح الترخيص الخاص بك.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'تم تعطيل مفتاح الترخيص الخاص بك لعنوان URL هذا. أعد تفعيله من <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> إدارة المواقع.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>عدم تطابق مفتاح الترخيص.</strong> الترخيص الذي أدخلته لا يتوافق مع إصدار TranslatePress المثبت لديك.</p><p>يُرجى التحقق من تثبيت الإصدار الصحيح لترخيصك من حساب TranslatePress الخاص بك.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'إذا كان لديك فقط الإضافة المجانية مثبتة ولكنك أضفت ترخيصًا مدفوعًا، يُرجى تثبيت الإضافة المدفوعة من حساب TranslatePress الخاص بك.','Your license key has reached its activation limit.'=>'بلغ مفتاح الترخيص الخاص بك الحد الأقصى للتفعيل.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'رقِّ خطتك لإضافة المزيد من المواقع. %1$sترقية الآن%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'تم تفعيل هذا الموقع بالفعل بترخيص مجاني. يمكن لكل موقع استخدام ترخيص مجاني واحد فقط.','An error occurred, please try again.'=>'حدث خطأ، يُرجى المحاولة مرة أخرى.','You have successfully activated your license'=>'تم تفعيل ترخيصك بنجاح','Others'=>'أخرى','Restrict by Language'=>'تقييد حسب اللغة','Exclude from Language'=>'استبعاد من اللغة','Restrict element to language'=>'تقييد العنصر بلغة','Show this element only in one language.'=>'عرض هذا العنصر بلغة واحدة فقط.','Enable translation'=>'تفعيل الترجمة','Allow translation to the corresponding language only if the content is written in the default language.'=>'السماح بالترجمة إلى اللغة المقابلة فقط إذا كان المحتوى مكتوبًا باللغة الافتراضية.','Select language'=>'اختر اللغة','Choose in which language to show this element.'=>'اختر اللغة التي تريد عرض هذا العنصر بها.','Exclude element from language'=>'استبعاد العنصر من اللغة','Exclude this element from specific languages.'=>'استبعاد هذا العنصر من لغات محددة.','Select languages'=>'اختر اللغات','Choose from which languages to exclude this element.'=>'اختر اللغات التي تريد استبعاد هذا العنصر منها.','This element will still be visible when you are translating your website through the Translation Editor.'=>'سيظل هذا العنصر مرئيًا عند ترجمة موقعك عبر محرر الترجمة.','The content of this element should be written in the default language.'=>'يجب كتابة محتوى هذا العنصر باللغة الافتراضية.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> واجه أخطاء SQL. <a href="%s" title="View TranslatePress SQL Errors">اطلع على الأخطاء</a>.','Automatic translation has been disabled.'=>'تم تعطيل الترجمة التلقائية.','Dismiss this notice.'=>'تجاهل هذا الإشعار.','Logged errors'=>'الأخطاء المسجلة','These are the most recent 5 errors logged by TranslatePress:'=>'هذه هي آخر 5 أخطاء سجّلها TranslatePress:','Yes'=>'نعم','Why are these errors occuring'=>'لماذا تحدث هذه الأخطاء','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'إذا اكتشف TranslatePress وجود خطأ ما أثناء تنفيذ الاستعلامات على قاعدة البيانات، فقد يقوم بتعطيل ميزة الترجمة التلقائية لتجنب أي رسوم إضافية من Google/DeepL. يجب تشغيل الترجمة التلقائية يدويًا بعد حل المشكلات.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'يمكن أن تحدث أخطاء SQL التي تم اكتشافها لأسباب مختلفة تشمل الجداول المفقودة، أو الصلاحيات المفقودة لمستخدم SQL لإنشاء جداول أو تنفيذ عمليات أخرى، أو المشكلات بعد ترحيل الموقع أو تغييرات في تكوين خادم SQL.','What you can do in this situation'=>'ما يمكنك فعله في هذه الحالة','Plan A.'=>'الخطة أ.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'انتقل إلى الإعدادات -> TranslatePress -> التبويب العام واحفظ الإعدادات. سيؤدي ذلك إلى إعادة إنشاء الجداول باستخدام إعدادات SQL الحالية. تحقق مما إذا كانت الأخطاء لم تعد تحدث أثناء تصفح موقعك بلغة مترجمة. انظر إلى الطوابع الزمنية للأخطاء للتأكد من أنك لا تشاهد الأخطاء القديمة. يتم عرض آخر 5 أخطاء فقط.','Plan B.'=>'الخطة ب.','If your problem isn\'t solved, try the following steps:'=>'إذا لم تُحَل مشكلتك، جرّب الخطوات التالية:','Create a backup of your database'=>'أنشئ نسخة احتياطية من قاعدة بياناتك','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'أنشئ نسخة من كل جدول ترجمة تواجه فيه أخطاء. يمكنك نسخ الجدول ضمن نفس قاعدة البيانات (trp_dictionary_en_us_es_es_COPY على سبيل المثال) -- نفّذ هذه الخطوة فقط إذا أردت الاحتفاظ بالترجمات الحالية','Remove the trouble tables by executing the DROP function on them'=>'أزِل الجداول المُسبِبة للمشاكل بتنفيذ أمر DROP عليها','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'انتقل إلى الإعدادات -> TranslatePress -> التبويب العام واحفظ الإعدادات. سيؤدي ذلك إلى إعادة إنشاء الجداول باستخدام خادم SQL الحالي.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'انسخ المحتوى ذا الصلة من الجداول المكررة (trp_dictionary_en_us_es_es_COPY على سبيل المثال) إلى الجدول الذي تم إنشاؤه حديثًا (trp_dictionary_en_us_es_es) -- نفّذ هذه الخطوة فقط إذا أردت الاحتفاظ بالترجمات الحالية','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'اختبر لترى إذا كان كل شيء يعمل. إذا حدث خطأ ما، يمكنك استعادة النسخة الاحتياطية التي أنشأتها في الخطوة الأولى. تحقق مما إذا كانت الأخطاء لم تعد تحدث أثناء تصفح موقعك بلغة مترجمة. انظر إلى الطوابع الزمنية للأخطاء للتأكد من أنك لا تشاهد الأخطاء القديمة. يتم عرض آخر 5 أخطاء فقط.','Plan C.'=>'الخطة ج.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'إذا لم تُحَل مشكلتك بعد، حاول أن تسأل مزود الاستضافة عن أخطائك. المشكلة الأكثر شيوعًا هي فقدان صلاحيات مستخدم SQL، مثل صلاحية إنشاء الجداول.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'تعذّر التثبيت. حاول مرة أخرى من <a href="%s" >لوحة تحكم الإضافات.</a>','Active'=>'نشط','Permission denied.'=>'تم رفض الإذن.','Invalid nonce.'=>'nonce غير صالح.','Settings scope unknown.'=>'نطاق الإعدادات غير معروف.','Legacy disabled.'=>'الوضع القديم معطل.','Language Switcher'=>'مبدّل اللغة','Change language to %s'=>'تغيير اللغة إلى %s','Automatic Translation'=>'الترجمة التلقائية','DeepL'=>'DeepL','Unsupported languages'=>'لغات غير مدعومة','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'لا يوفّر محرّك الترجمة التلقائية المحدّد دعمًا لهذه اللغات.<br/>لا يزال بإمكانك ترجمة الصفحات بهذه اللغات يدويًا باستخدام محرّر الترجمة.','API key validation failed.'=>'فشل التحقق من مفتاح API.','API key verification was successful.'=>'تم التحقق من مفتاح API بنجاح.','Please enter your Google Translate key.'=>'يُرجى إدخال مفتاح Google Translate.','Please enter your DeepL API key.'=>'يُرجى إدخال مفتاح DeepL API.','Not TranslatePress onboarding page.'=>'ليست صفحة الإعداد الأولي لـ TranslatePress.','Step %s does not exist'=>'الخطوة %s غير موجودة','Welcome'=>'مرحبًا','Add Languages'=>'إضافة لغات','Enable Addons'=>'تفعيل الإضافات','Finalize'=>'إنهاء','Exit Setup'=>'خروج من الإعداد','Upgrade'=>'ترقية','Nothing here'=>'لا يوجد شيء هنا','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'ترخيص <strong>TranslatePress</strong> مفقود أو غير صالح. <br/>يُرجى %1$sتسجيل نسختك%2$s لتفعيل الترجمة التلقائية للموقع عبر TranslatePress AI، والإضافات المتميزة، والتحديثات التلقائية، والدعم. هل تحتاج إلى مفتاح ترخيص؟ %3$sاشترِ واحدًا الآن%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'سينتهي ترخيص <strong>TranslatePress</strong> في %1$s. يُرجى %2$sتجديد ترخيصك%3$s للاستمرار في الحصول على الوصول إلى الترجمات التلقائية عبر TP AI، والإضافات المتميزة، وتنزيلات المنتج، والتحديثات التلقائية. %4$sجدّد الآن%5$s','Error: '=>'خطأ: ','Something went wrong, please try again.'=>'حدث خطأ ما، يُرجى المحاولة مرة أخرى.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'انتهى ترخيص <strong>TranslatePress</strong>. <br/>يُرجى %1$sتجديد ترخيصك%2$s للاستمرار في الحصول على الوصول إلى الترجمات التلقائية عبر TranslatePress AI، والإضافات المتميزة، وتنزيلات المنتج، والتحديثات التلقائية. %3$sجدّد الآن %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'عدم تطابق مفتاح الترخيص. الترخيص الذي أدخلته لا يتوافق مع إصدار <strong>%1$s</strong> المثبت لديك. <br/>يُرجى التحقق من تثبيت الإصدار الصحيح لترخيصك من %2$sحساب TranslatePress%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>إذا كان لديك فقط الإضافة المجانية مثبتة ولكنك أضفت ترخيصًا مدفوعًا، يُرجى تثبيت الإضافة المدفوعة من حساب TranslatePress الخاص بك.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'لقد وصلت إلى حد التفعيل لترخيص <strong>%1$s</strong> الخاص بك. <br/>أدرِر مواقعك النشطة من %2$s حسابك %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'تم تعطيل ترخيصك لهذا URL. أعِد تفعيله من <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> إدارة المواقع.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'ترجمة %1$s التلقائية تتطلب ترخيصًا نشطًا. يُرجى %2$sتجديد%3$s ترخيصك أو شراء ترخيص جديد %4$sمن هنا%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'يُرجى %1$sإدخال%2$s مفتاح الترخيص لتفعيل ترجمة %3$s التلقائية.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'تبقّى لديك أقل من 5000 كلمة من TranslatePress AI. للاستمرار في ترجمة موقعك تلقائيًا، يُرجى %sشراء كلمات AI إضافية بخصم من حسابك%s.',' Error: '=>' خطأ: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'تم تفعيل هذا الموقع بالفعل بترخيص مجاني. يمكن لكل موقع استخدام ترخيص مجاني واحد فقط. يُرجى الترقية إلى خطة متميزة للحصول على المزيد من كلمات TranslatePress AI من %1$s حسابك %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'ليس لديك ترخيص صالح لـ <strong>TranslatePress</strong>. %1$sاحصل على واحد مجانًا%2$s للوصول إلى TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>جديد:</strong> إضافة <strong>نطاق مختلف لكل لغة</strong> متوفرة الآن! عزّز SEO العالمي الخاص بك وأنشئ تجربة محلية باستخدام نطاقات خاصة بالبلدان مثل .de أو .fr. رقِّ إلى <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business أو Developer</a> للوصول إليها + المزيد من المزايا المتميزة!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>جديد:</strong> إضافة <strong>نطاق مختلف لكل لغة</strong> متوفرة الآن! عزّز SEO العالمي الخاص بك وأنشئ تجربة محلية باستخدام نطاقات خاصة بالبلدان مثل .de أو .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">اعرف المزيد</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'تم تجاوز الحصة اليومية لأحرف الترجمة الآلية. يُرجى التحقق من صفحة <strong>TranslatePress -> <a href="%s">الترجمة التلقائية</a></strong> لمزيد من المعلومات.','Marketing optin'=>'الاشتراك في التسويق','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'اشترك في إشعارات تحديثات الأمان والميزات، والتتبع التشخيصي غير الحساس.','TranslatePress Preferred User Language'=>'لغة المستخدم المفضلة في TranslatePress','Preferred language to navigate the site'=>'اللغة المفضلة لتصفح الموقع','The language is automatically set based by the last visited language by the user.'=>'يتم تعيين اللغة تلقائيًا بناءً على آخر لغة زارها المستخدم.','Always use this language'=>'استخدم هذه اللغة دائمًا','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'بتحديد هذا الإعداد ستظل اللغة المفضلة هي التي تم اختيارها أعلاه، دون إمكانية تغييرها في الواجهة الأمامية.<br>سيتم استخدام هذه اللغة في عمليات مختلفة مثل إرسال بريد إلكتروني إلى المستخدم.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'مرحبًا! يبدو أنك تستخدم <strong>TranslatePress</strong> منذ فترة لترجمة موقعك. هذا رائع! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'إذا أمكنك تخصيص بضع لحظات لتقييمه على WordPress.org فسيساعدنا ذلك كثيرًا (ويعزز دافعي).','~ Razvan, developer of TranslatePress'=>'~ Razvan، مطوّر TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'قيّم TranslatePress على صفحة الإضافة في WordPress.org','Ok, I will gladly help!'=>'حسنًا، سأساعد بكل سرور!','No, thanks.'=>'لا، شكرًا.','Full Language Names'=>'أسماء اللغات الكاملة','Short Language Names'=>'أسماء اللغات المختصرة','Flags with Full Language Names'=>'أعلام مع أسماء اللغات الكاملة','Flags with Short Language Names'=>'أعلام مع أسماء اللغات المختصرة','Only Flags'=>'أعلام فقط','Full Language Names No HTML'=>'أسماء اللغات الكاملة بدون HTML','Bottom Right'=>'أسفل اليمين','Bottom Left'=>'أسفل اليسار','Top Right'=>'أعلى اليمين','Top Left'=>'أعلى اليسار','Dark'=>'داكن','Light'=>'فاتح','Deactivate'=>'تعطيل','Activate'=>'تفعيل','Invalid language code. Please try again.'=>'رمز اللغة غير صالح. يُرجى المحاولة مرة أخرى.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'يمكن أن تحتوي رموز اللغة على الأحرف A-Z a-z 0-9 - _ فقط. تحقق من رموز اللغة في إعدادات TranslatePress العامة.','Error! Duplicate URL slug values.'=>'خطأ! قيم URL slug مكررة.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'لا يمكنك اختيار لغتين لهما نفس <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">رمز iso</a> ولكن بمستويات رسمية مختلفة، لأن ذلك سيؤدي إلى <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">وسوم hreflang</a> مكررة.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'تم اكتشاف لغة مكررة.<br>يمكن إضافة كل لغة مرة واحدة فقط لضمان إدارة دقيقة للترجمة.<br> يُرجى تغيير إدخال اللغة المكررة والمحاولة مرة أخرى. ','Current Language'=>'اللغة الحالية','Opposite Language'=>'اللغة المقابلة','General'=>'عام','Translate Site'=>'ترجمة الموقع','Addons'=>'الإضافات','License'=>'الترخيص','Settings'=>'الإعدادات','Activate License'=>'تفعيل الترخيص','Pro Features'=>'الميزات الاحترافية','Need Help?'=>'هل تحتاج إلى مساعدة؟','Recent community discussions'=>'أحدث مناقشات المجتمع','Loading...'=>'جارٍ التحميل...','Unable to load forum posts'=>'تعذّر تحميل منشورات المنتدى','Ask a Question'=>'اطرح سؤالاً','View All Topics'=>'عرض جميع المواضيع','by'=>'بواسطة','Have a question?'=>'هل لديك سؤال؟','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'احصل على المساعدة مباشرة من مطوّري الإضافة، واقترح تحسينات، أو شارك ملاحظاتك!','Tip for faster help:'=>'نصيحة للحصول على مساعدة أسرع:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'اذكر ما جرّبته، وما توقعته، وما حدث. تساعد لقطات الشاشة!','Toggle support chat'=>'تبديل دردشة الدعم','Ask the community'=>'اسأل المجتمع','Close'=>'إغلاق','Empty feed response'=>'استجابة خلاصة فارغة','Unable to parse feed'=>'تعذّر تحليل الخلاصة','Just now'=>'للتو','%d hour ago'=>'منذ %d ساعات' . "\0" . 'منذ ساعة' . "\0" . 'منذ ساعتين' . "\0" . 'منذ %d ساعات' . "\0" . 'منذ %d ساعة' . "\0" . 'منذ %d ساعة','%d day ago'=>'منذ %d أيام' . "\0" . 'منذ يوم' . "\0" . 'منذ يومين' . "\0" . 'منذ %d أيام' . "\0" . 'منذ %d يوم' . "\0" . 'منذ %d يوم','Source'=>'المصدر','Srcset'=>'مجموعة المصادر','Alt attribute'=>'سمة النص البديل','Title attribute'=>'سمة العنوان','Anchor link'=>'رابط المرساة','Placeholder attribute'=>'سمة العنصر النائب','Submit attribute'=>'سمة الإرسال','Text'=>'النص','Video Poster'=>'ملصق الفيديو','plural form'=>'صيغة الجمع','one'=>'واحد','few'=>'قليل','many'=>'كثير','other'=>'آخر','Saved'=>'تم الحفظ','Save'=>'حفظ','Saving translation...'=>'جاري حفظ الترجمة...','You have unsaved changes!'=>'لديك تغييرات غير محفوظة!','Discard changes'=>'تجاهل التغييرات','Discard All'=>'تجاهل الكل','Loading Strings...'=>'جارٍ تحميل السلاسل...','Select string to translate...'=>'حدد سلسلة للترجمة...','Close Editor'=>'إغلاق المحرر','From'=>'من','To'=>'إلى','Add Media'=>'إضافة وسائط','Other languages'=>'لغات أخرى','Context'=>'السياق','View Website As'=>'عرض الموقع كـ','Available in our Pro Versions'=>'متاح في نسخنا الاحترافية','Select or Upload Media'=>'حدد أو ارفع وسائط','Use this media'=>'استخدم هذه الوسائط','Translate'=>'ترجمة','Translate entire block element'=>'ترجمة عنصر الكتلة بالكامل','Split block to translate strings individually'=>'قسّم الكتلة لترجمة السلاسل بشكل فردي','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'حفظ التغييرات على الترجمة. اختصار: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'انتقل إلى السلسلة التالية في القائمة المنسدلة. اختصار: CTRL(⌘) + ALT + سهم يمين','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'انتقل إلى السلسلة السابقة في القائمة المنسدلة. اختصار: CTRL(⌘) + ALT + سهم يسار','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'تجاهل جميع التغييرات. اختصار: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'تجاهل التغييرات في مربع النص هذا. لتجاهل التغييرات في جميع مربعات النص استخدم الاختصار: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'تجاهل التلميح','Quick Intro'=>'مقدمة سريعة','Are you sure you want to split this phrase into smaller parts?'=>'هل أنت متأكد أنك تريد تقسيم هذه العبارة إلى أجزاء أصغر؟','This string is not ready for translation yet. <br>Try again in a moment...'=>'هذه السلسلة ليست جاهزة للترجمة بعد. <br>حاول مجددًا بعد لحظات...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'لكي يعمل هذا الخيار، يُرجى تحديث إضافة التصفح بدور آخر إلى أحدث إصدار.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'لترجمة slugs، يُرجى تحديث إضافة SEO Pack إلى أحدث إصدار.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'يمكنك إضافة لغة جديدة من <a href="%s">الإعدادات->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'ومع ذلك، لا يزال بإمكانك استخدام TranslatePress لتعديل <strong style="background: #f5fb9d;">سلاسل gettext</strong> المتاحة في صفحتك.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'لا يمكن تعديل السلاسل التي أنشأها المستخدم، فقط تلك الموجودة في القوالب والإضافات.','Extra Translation Features'=>'ميزات الترجمة الإضافية','Support for 130+ Extra Languages'=>'دعم 130+ لغة إضافية','Access to TranslatePress AI'=>'الوصول إلى TranslatePress AI','Translate SEO Title, Description, Slug'=>'ترجمة عنوان SEO، والوصف، وSlug','Publish only when translation is complete'=>'النشر فقط عند اكتمال الترجمة','Translate by Browsing as User Role'=>'الترجمة بالتصفح بدور مستخدم','Different Menu Items for each Language'=>'عناصر قائمة مختلفة لكل لغة','Automatic User Language Detection'=>'الكشف التلقائي عن لغة المستخدم','Upgrade to PRO'=>'الترقية إلى PRO','Upgrade to PRO with our biggest discount of the year!'=>'الترقية إلى PRO مع أكبر خصم لدينا هذا العام!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'في هذا الجمعة السوداء، احصل على الوصول إلى هذه الميزات والمزيد بجزء بسيط من التكاليف:','No available suggestions'=>'لا توجد اقتراحات متاحة','Suggestions from translation memory'=>'اقتراحات من ذاكرة الترجمة','Click to Copy'=>'انقر للنسخ','Human Translation'=>'الترجمة البشرية','Machine Translation'=>'الترجمة الآلية','Text on this page is %s% translated into all languages.'=>'تم ترجمة %s% من النص الموجود في هذه الصفحة إلى جميع اللغات.','%1$s% of text on this page is translated into %2$s.'=>'تم ترجمة %1$s% من النص الموجود في هذه الصفحة إلى %2$s.','This page is %1$s% translated into %2$s.'=>'تم ترجمة %1$s% من هذه الصفحة إلى %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Slug الذي تحاول تعديله موجود في أنواع slug أخرى: %s. سيؤدي تعديله إلى استبدال كل تكرار، بغض النظر عن النوع الحالي.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'مرّر مؤشر الفأرة فوق أي نص في الصفحة، وانقر %s،<br> ثم عدّل الترجمة في الشريط الجانبي.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'لا تنسَ حفظ الترجمة. استخدم اختصار لوحة المفاتيح CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'بدّل اللغة لترى تغييرات الترجمة مباشرةً على الصفحة.','Search for any text in this page in the dropdown.'=>'ابحث عن أي نص في هذه الصفحة في القائمة المنسدلة.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'ترخيص %s الخاص بك <span class="trp-license-status-emphasized">منتهي الصلاحية</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'يُرجى تجديد ترخيصك للاستمرار في الحصول على الوصول إلى TranslatePress AI، والإضافات المميزة، والتحديثات التلقائية، والدعم.','Renew Now'=>'جدّد الآن','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>في الجمعة السوداء هذا العام، جدّد ترخيصك بسعر مميز</strong> للاستمرار في الحصول على الوصول إلى تنزيلات المنتج، والتحديثات التلقائية، والدعم.','Get Deal'=>'احصل على العرض','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'تم <span class="trp-license-status-emphasized">استرداد</span> ترخيص %s الخاص بك.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'يُرجى شراء ترخيص جديد للاستمرار في الحصول على الوصول إلى TranslatePress AI، والإضافات المميزة، والتحديثات التلقائية، والدعم.','Purchase a new license'=>'شراء ترخيص جديد','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'ترخيص %s الخاص بك <span class="trp-license-status-emphasized">مفقود أو غير صالح</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'يُرجى إدخال ترخيص صالح للوصول إلى TranslatePress AI، والإضافات المميزة، والتحديثات التلقائية، والدعم. أتحتاج إلى مفتاح ترخيص؟ %1$sاشترِ واحدًا الآن%2$s','Enter a valid license'=>'أدخل ترخيصًا صالحًا','Slugs'=>'Slugs','Meta Information'=>'البيانات الوصفية','String List'=>'قائمة السلاسل','Gettext Strings'=>'سلاسل Gettext','Images'=>'الصور','Videos'=>'الفيديوهات','Audios'=>'الملفات الصوتية','Dynamically Added Strings'=>'سلاسل مضافة ديناميكيًا','Translation Editor'=>'محرر الترجمة','Edit translations by visually selecting them on each site page'=>'حرّر الترجمات بتحديدها بصريًا على كل صفحة من صفحات الموقع','String Translation'=>'ترجمة السلاسل','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'تعديل ترجمات URL slug، وترجمة الإضافات والقالب (رسائل البريد، النماذج، إلخ.)','Current User'=>'المستخدم الحالي','Logged Out'=>'غير مسجل الدخول','Translate Page'=>'ترجمة الصفحة','Add a New Language'=>'إضافة لغة جديدة','Get a Free AI License'=>'احصل على ترخيص ذكاء اصطناعي مجاني','Your License is Invalid'=>'ترخيصك غير صالح','Get More AI Words (%d left)'=>'احصل على المزيد من كلمات الذكاء الاصطناعي (%d متبقي)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'يفتح المنشور في محرر الترجمة. يجب حفظ المنشور كمسودة أو نشره مسبقًا.','Security check'=>'فحص الأمان','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>تحذير:</strong> بعض السلاسل قد تحتوي على محارف مشفّرة بشكل غير صحيح. قد يؤدي ذلك إلى تعطيل الاستعلامات، مما يجعل الصفحة غير مترجمة في الوضع المباشر. يُنصح بمراجعة السلاسل التالية أو طريقة إخراجها.','TranslatePress data update'=>'تحديث بيانات TranslatePress','We need to update your translations database to the latest version.'=>'نحتاج إلى تحديث قاعدة بيانات الترجمات الخاصة بك إلى أحدث إصدار.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'سيسمح التحديث بتحرير ترجمات النصوص المحلية من الإضافات والقالب. ستظل الترجمة الحالية تعمل كما هو متوقع.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'هام: يُنصح بشدة بأخذ نسخة احتياطية من قاعدة البيانات أولاً!
هل أنت متأكد أنك تريد المتابعة؟','Run the updater'=>'تشغيل المحدّث','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'سيسمح التحديث بتحرير ترجمات الأسماء اللطيفة. ستظل الترجمة الموجودة تعمل كما هو متوقع.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'يُرجى تفعيل ملحق SEO من<br/>WordPress -> الإعدادات -> TranslatePress -> قسم الملحقات','Go to Addons'=>'الذهاب إلى الملحقات','The SEO Pack add-on allows translation of all the URL slugs:'=>'تتيح إضافة SEO Pack ترجمة جميع الأسماء اللطيفة لعناوين URL:','Taxonomy slugs'=>'الأسماء اللطيفة للتصنيفات','Term slugs'=>'الأسماء اللطيفة للمصطلحات','Post slugs (this includes pages and custom post types)'=>'الأسماء اللطيفة للمقالات (يتضمن ذلك الصفحات وأنواع المنشورات المخصصة)','Post type base slugs'=>'الأسماء اللطيفة لأساس أنواع المنشورات','WooCommerce slugs'=>'الأسماء اللطيفة لـ WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'ملحق SEO Pack متاح مع جميع النسخ المدفوعة من الإضافة.','Upgrade to Pro'=>'الترقية إلى Pro','Description'=>'الوصف','Article Section'=>'قسم المقالة','Article Tag'=>'وسم المقالة','OG Title'=>'عنوان OG','OG Site Name'=>'اسم موقع OG','OG Description'=>'وصف OG','OG Image Alt'=>'النص البديل لصورة OG','Twitter Title'=>'عنوان Twitter','Twitter Description'=>'وصف Twitter','Twitter Image Alt'=>'النص البديل لصورة Twitter','Page Title'=>'عنوان الصفحة','Dublin Core Title'=>'عنوان Dublin Core','Dublin Core Description'=>'وصف Dublin Core','OG Image'=>'صورة OG','OG Image Secure URL'=>'رابط URL الآمن لصورة OG','Twitter Image'=>'صورة Twitter','Removing cdata dictionary strings for language %s...'=>'جارٍ إزالة سلاسل قاموس CDATA للغة %s...','Removing untranslated dictionary links for language %s...'=>'جارٍ إزالة روابط القاموس غير المترجمة للغة %s...','Removing duplicated gettext strings for language %s...'=>'جارٍ إزالة سلاسل Gettext المكررة للغة %s...','Removing duplicated dictionary strings for language %s...'=>'جارٍ إزالة سلاسل القاموس المكررة للغة %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'جارٍ إزالة سلاسل القاموس غير المترجمة التي تتوفر ترجمتها للغة %s...','Inserting original strings for language %s...'=>'جارٍ إدراج السلاسل الأصلية للغة %s...','Cleaning original strings table for language %s...'=>'جارٍ تنظيف جدول السلاسل الأصلية للغة %s...','Updating original string ids for language %s...'=>'جارٍ تحديث معرّفات السلاسل الأصلية للغة %s...','Regenerating original meta table for language %s...'=>'جارٍ إعادة إنشاء جدول البيانات الوصفية الأصلية للغة %s...','Cleaning original meta table for language %s...'=>'جارٍ تنظيف جدول البيانات الوصفية الأصلية للغة %s...','Replacing original id NULL with value for language %s...'=>'جارٍ استبدال معرّف NULL الأصلي بقيمة للغة %s...','Inserting gettext original strings for language %s...'=>'جارٍ إدراج سلاسل Gettext الأصلية للغة %s...','Cleaning gettext original strings table for language %s...'=>'جارٍ تنظيف جدول سلاسل Gettext الأصلية للغة %s...','Updating gettext original string ids for language %s...'=>'جارٍ تحديث معرّفات سلاسل Gettext الأصلية للغة %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'جارٍ ترحيل الأسماء اللطيفة للتصنيفات والأسماء اللطيفة لأساس أنواع المنشورات إلى بنية الجدول الجديدة...','Migrating post slugs to new table structure for language %s...'=>'جارٍ ترحيل الأسماء اللطيفة للمقالات إلى بنية الجدول الجديدة للغة %s...','Migrating term slugs to new table structure for language %s...'=>'جارٍ ترحيل مصطلحات slug إلى بنية الجدول الجديدة للغة %s...','Finishing up...'=>'جارٍ الانتهاء...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'لم تكتمل عملية تحسين قاعدة البيانات بنجاح. نوصي باستعادة قاعدة البيانات الأصلية أو <a href="%s" >المحاولة مرة أخرى.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'تم إيقاف التحديث! حساب المستخدم الخاص بك لا يملك الصلاحية اللازمة لإجراء تحديثات قاعدة البيانات.','Update aborted! Invalid nonce.'=>'تم إيقاف التحديث! nonce غير صالح.','Update aborted! Incorrect action.'=>'تم إيقاف التحديث! إجراء غير صحيح.','Update aborted! Incorrect language code.'=>'تم إلغاء التحديث! رمز اللغة غير صحيح.','Updating database to version %s+'=>'جاري تحديث قاعدة البيانات إلى الإصدار %s+','Processing table for language %s...'=>'جاري معالجة الجدول للغة %s...','Back to TranslatePress Settings'=>'العودة إلى إعدادات TranslatePress','Successfully updated database!'=>'تم تحديث قاعدة البيانات بنجاح!',' done.'=>' تم.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'جميع إضافات TranslatePress الفردية <a href="%1$s" target="_blank">تم إيقافها</a> وأصبحت الآن مضمنة في إصدارات TranslatePress المتميزة الشخصية والتجارية والمطورين. يُرجى تسجيل الدخول إلى <a href="%2$s" target="_blank">صفحة حسابك</a>، وتنزيل الإصدار المتميز الجديد وتثبيته. سيتم نقل إعدادات الإضافات الفردية الخاصة بك.','Brand-new Language Switcher Settings are here!'=>'إعدادات محوّل اللغة الجديدة كليًا متوفرة هنا!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'استكشف القوالب الجاهزة، وألوان المحوّل، وأنماط الأعلام، والتباعد، والتخطيطات وغيرها. استخدم المعاينة المباشرة لتحسين محوّلك في ثوانٍ.','Start customizing'=>'ابدأ التخصيص','Read documentation'=>'قراءة التوثيق','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> يتطلب <strong><a href="http://php.net/manual/en/book.mbstring.php">مكتبة PHP للسلاسل متعددة البايتات</a></strong>. يُرجى التواصل مع مسؤول خادمك لتثبيتها.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'تم اكتشاف قيود الاستعلامات الطويلة على استضافة WPEngine. قد تظهر بعض الصفحات الكبيرة غير مترجمة. يمكنك إزالة القيد بإضافة ما يلي إلى ملف wp-config.php الخاص بموقعك: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'علم اللغة المخصص','The Language code of the added custom language cannot be empty.'=>'لا يمكن أن يكون رمز اللغة للغة المخصصة المضافة فارغًا.','The Language code of the added custom language is invalid.'=>'رمز اللغة للغة المخصصة المضافة غير صالح.','The Automatic Translation Code of the added custom language is invalid.'=>'رمز الترجمة التلقائية للغة المخصصة المضافة غير صالح.','TranslatePress Add-ons'=>'إضافات TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'يجب عليك شراء هذا الإصدار أولاً للوصول إلى الإضافة %1$sهنا%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'يُرجى %1$sإدخال مفتاح الترخيص%2$s أولاً، لتفعيل هذه الإضافة.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'أنت بحاجة إلى ترخيص نشط للوصول إلى الإضافة. جدّد الترخيص أو اشتري واحداً جديداً %1$sهنا%2$s.','Advanced Add-ons'=>'إضافات متقدمة','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'تُوسّع هذه الإضافات مُكوّن الترجمة الخاص بك، وهي متوفّرة في خطط Developer وBusiness وPersonal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (القديم)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'دعم SEO لـ slug الصفحة، وعنوان الصفحة، والوصف، ومعلومات الرسم البياني الاجتماعي لفيسبوك وتويتر. يتم ضبط سمة lang في HTML بشكل صحيح.','Multiple Languages'=>'لغات متعددة','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'أضف ما تشاء من اللغات لمشروعك ليصبح عالمياً. انشر لغتك فقط عندما تكتمل جميع الترجمات.','Pro Add-ons'=>'إضافات احترافية','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'تُوسّع هذه الإضافات مُكوّن الترجمة الخاص بك، وهي متوفّرة في خطط Business وDeveloper.','DeepL Automatic Translation'=>'الترجمة التلقائية DeepL','Automatically translate your website through the DeepL API.'=>'ترجمة موقعك تلقائياً عبر DeepL API.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'يُطالِب الزوّار بالتبديل إلى لغتهم المفضلة بناءً على إعدادات المتصفح أو عنوان IP، ويتذكر آخر لغة تمت زيارتها.','Translator Accounts'=>'حسابات المترجمين','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'أنشئ حسابات مترجمين لمستخدمين جدد أو اسمح للمستخدمين الحاليين غير الإداريين بترجمة موقعك.','Browse As User Role'=>'التصفح بدور مستخدم','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'تصفّح موقعك كما يفعل دور مستخدم معين. مفيد جداً للمحتوى الديناميكي أو المحتوى المخفي الذي يظهر لمستخدمين معينين.','Navigation Based on Language'=>'التنقل بناءً على اللغة','Configure different menu items for different languages.'=>'اضبط عناصر قائمة مختلفة للغات مختلفة.','Different Domain per Language'=>'نطاق مختلف لكل لغة','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'اربط نطاقات أو نطاقات فرعية منفصلة بكل إصدار مترجم. عزّز هوية علامتك التجارية المحلية وحسّن أداء SEO لكل لغة تدعمها.','Recommended Plugins'=>'إضافات موصى بها','A short list of plugins you can use to extend your website.'=>'قائمة مختصرة من الإضافات التي يمكنك استخدامها لتوسيع موقعك.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'التقط المزيد من معلومات المستخدم في نموذج التسجيل بمساعدة حقول ملف تعريف المستخدم المخصصة في Profile Builder و/أو أضف عملية تأكيد البريد الإلكتروني للتحقق من حسابات عملائك.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'اقبل المدفوعات من المستخدمين، وأنشئ خطط اشتراك، وقيّد المحتوى على موقع العضوية الخاص بك.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'أنشئ أتمتة وسير عمل بدون برمجة على موقع WordPress الخاص بك. اربط إضافاتك ومواقعك وتطبيقاتك بسهولة معًا.','Save Changes'=>'حفظ التغييرات','TranslatePress Errors'=>'أخطاء TranslatePress','There are no logged errors.'=>'لا توجد أخطاء مسجلة.','Change language'=>'تغيير اللغة','Website language selector'=>'محدد لغة الموقع','WordPress Translation Plugin'=>'إضافة ترجمة WordPress','Available languages'=>'اللغات المتاحة','Language Switcher update notice'=>'إشعار تحديث مبدّل اللغة','Legacy language switcher is currently enabled'=>'مبدّل اللغة القديم مفعّل حاليًا','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'لقد قمنا بترقية المبدّل لتخصيص أكثر ثراءً وتجربة مستخدم أفضل.<br>لاستخدام المُكوّن الجديد، عطّل <strong>تحميل مبدّل اللغة القديم</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'ملاحظة: يمكنك العودة في أي وقت من <strong>الإعدادات المتقدمة → <a href="%s">استكشاف الأخطاء وإصلاحها</a></strong>.','Enable the new switcher'=>'تفعيل المبدّل الجديد','Your License Key is valid.'=>'مفتاح الترخيص الخاص بك صالح.','Your License Key is invalid.'=>'مفتاح الترخيص الخاص بك غير صالح.','Your License has expired.'=>'انتهت صلاحية ترخيصك.','Deactivate License'=>'إلغاء تنشيط الترخيص','Add a license key'=>'إضافة مفتاح ترخيص','License Key'=>'مفتاح الترخيص','Manage your license in your %1$s.'=>'أدر ترخيصك في %1$s.','Account Page'=>'صفحة الحساب','Don’t have a TranslatePress AI License Key?'=>'ليس لديك مفتاح ترخيص TranslatePress AI؟','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'يمكنك الحصول على واحد %1$sمجاناً%2$s، من خلال إنشاء حساب مجاني. يتضمن:','Access to TranslatePress AI for instant automatic translations'=>'الوصول إلى TranslatePress AI للترجمات الآلية الفورية','2000 AI words to translate automatically'=>'2000 كلمة بالذكاء الاصطناعي للترجمة الآلية','Get a free License Today'=>'احصل على ترخيص مجاني اليوم','Debug Information'=>'معلومات التصحيح','Debug Data for License Checking'=>'بيانات التصحيح للتحقق من الترخيص','Debug Data for License Activation'=>'بيانات التصحيح لتنشيط الترخيص','Get more AI words and unlock all features with TranslatePress Pro.'=>'احصل على المزيد من كلمات الذكاء الاصطناعي وافتح كل الميزات باستخدام TranslatePress Pro.','Upgrade now ↗'=>'الترقية الآن ↗','Already purchased a Premium version?'=>'هل اشتريتَ النسخة المميزة بالفعل؟','Go to your %1$s'=>'انتقل إلى %1$s','TranslatePress.com Account'=>'حساب TranslatePress.com','Download & Install the Pro plugin'=>'تنزيل وتثبيت إضافة Pro','Learn More'=>'معرفة المزيد','Get a translation volume estimate with a detailed breakdown per page'=>'احصل على تقدير حجم الترجمة مع تقسيم مفصّل لكل صفحة','Find how many translatable words are on your website'=>'اكتشف عدد الكلمات القابلة للترجمة في موقعك','Enable Automatic Translation'=>'تفعيل الترجمة التلقائية','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'لاستخدام <strong>DeepL</strong> للترجمة التلقائية، فعّل إضافة Pro هذه من <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'التّرجمة التلقائية باستخدام <strong>DeepL</strong> متاحة كـ <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'بترقيتك، ستحصل على حق الوصول إلى جميع الإضافات المدفوعة والدعم المميز، كما ستساعد في تمويل التطوير المستقبلي لـ TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'يرجى ملاحظة أن استخدام DeepL API مدفوع بشكل منفصل. راجع <a href="https://www.deepl.com/pro.html#developer">معلومات تسعير DeepL</a>.','TranslatePress Pro Add-ons'=>'إضافات TranslatePress Pro','Test API credentials'=>'اختبار بيانات اعتماد API','Check if the selected translation engine is configured correctly.'=>'تحقق مما إذا كان محرك الترجمة المحدد مهيأ بشكل صحيح.','Alternative Engines'=>'محركات بديلة','Switch to TranslatePress AI'=>'التبديل إلى TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'دمج الترجمة الآلية مباشرةً مع موقع WordPress الخاص بك.','More info'=>'مزيد من المعلومات','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'اختر المحرك الذي تريد استخدامه من أجل %1$s ترجمة موقعك تلقائيًا.','Automatic Translation Settings'=>'إعدادات الترجمة التلقائية','AI Words Low Notification'=>'إشعار انخفاض كلمات TranslatePress AI','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'ستتلقّى إشعارًا بالبريد الإلكتروني عندما ينخفض عدد كلمات TranslatePress AI عن الحد المحدد.','This feature is only available when using the TranslatePress AI translation engine.'=>'تتوفر هذه الميزة فقط عند استخدام محرك ترجمة TranslatePress AI.','Notification Email'=>'بريد الإشعارات','The email address where the low AI words notification will be sent.'=>'عنوان البريد الإلكتروني الذي سيُرسل إليه إشعار انخفاض كلمات TranslatePress AI.','Word Threshold'=>'حد الكلمات','words'=>'كلمات','You will be notified when remaining AI words drop below this number.'=>'سيتم إشعارك عندما تنخفض كلمات TranslatePress AI المتبقية عن هذا العدد.','Automatically Translate Slugs'=>'ترجمة slugs تلقائيًا','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'إنشاء ترجمات تلقائية لـ slugs للمقالات والصفحات وأنواع المنشورات المخصصة.<br/>سيتم ترجمة slugs تلقائيًا بدءًا من التحديث الثاني لكل صفحة.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'تتوفر هذه الميزة فقط في النسخة المدفوعة. رقِّ TranslatePress وافتح المزيد من الميزات المميزة.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'يتطلب تثبيت وتفعيل <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">إضافة SEO Pack</a>.','Upgrade now'=>'الترقية الآن','Block Crawlers'=>'حظر برامج الزحف','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'حظر برامج الزحف من تشغيل الترجمات التلقائية على موقعك.<br>لن يمنع ذلك برامج الزحف من الوصول إلى صفحات هذا الموقع.','Limit machine translation / characters per day'=>'تحديد حد الترجمة الآلية / الأحرف في اليوم','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'أضف حدًا لعدد الأحرف المترجمة تلقائيًا لتخطيط ميزانية مشروعك بشكل أفضل.','characters per day'=>'أحرف في اليوم','Today\'s Character Count: '=>'عدد أحرف اليوم: ','Log machine translation queries.'=>'تسجيل استعلامات الترجمة الآلية.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'فعّله فقط لأغراض الاختبار. قد يؤثر على الأداء.<br>تُخزّن جميع السجلات في جدول قاعدة البيانات wp_trp_machine_translation_log. استخدم إضافة مثل <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> لاستعراض السجلات أو مباشرةً من مدير قاعدة البيانات لديك (PHPMyAdmin، وما إلى ذلك).','Test API Credentials'=>'اختبار بيانات اعتماد API','HTTP Referrer: '=>'مرجع HTTP: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'استخدم مرجع HTTP هذا إذا كانت API تتيح لك تقييد استخدام المفتاح من لوحة التحكم الخاصة بها.','Response'=>'الاستجابة','Response Body'=>'نص الاستجابة','Entire Response From wp_remote_get():'=>'الاستجابة الكاملة من wp_remote_get():','All Languages'=>'جميع اللغات','Select the languages you wish to make your website available in.'=>'حدد اللغات التي تريد أن يكون موقعك متاحًا بها.','Formality'=>'الرسمية','Code'=>'الرمز','Slug'=>'Slug','Default'=>'افتراضي','Formal'=>'رسمي','Informal'=>'غير رسمي','Language'=>'اللغة','This language does not support formality. '=>'هذه اللغة لا تدعم الرسمية. ','Are you sure you want to remove this language?'=>'هل أنت متأكد أنك تريد إزالة هذه اللغة؟','Custom Languages'=>'لغات مخصصة','To Add more languages activate the Multiple Languages Addon'=>'لإضافة المزيد من اللغات، فعّل إضافة اللغات المتعددة','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'تحتاج إلى ترخيص نشط لإضافة المزيد من اللغات. تحقق في %1$sحسابك%2$s من أن ترخيصك صالح.','Please %1$senter your license%2$s key first to add more languages.'=>'يُرجى %1$sإدخال مفتاح ترخيصك%2$s أولاً لإضافة المزيد من اللغات.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'إضافة أكثر من لغتين هي ميزة مدفوعة. رقِّ TranslatePress لإتاحة المزيد من الميزات المتميزة.','Website Languages'=>'لغات الموقع','Default Language'=>'اللغة الافتراضية','Select the language your content is written in.'=>'حدد اللغة التي كُتب بها محتواك.','WARNING. Changing the default language will invalidate existing translations.'=>'تحذير. تغيير اللغة الافتراضية سيلغي صلاحية الترجمات الموجودة.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'حتى التغيير من en_US إلى en_GB، لأنهما يُعاملان كلغتين مختلفتين.','In most cases changing the default flag is all it is needed: '=>'في معظم الحالات، تغيير العلم الافتراضي هو كل ما يلزم: ','replace the default flag'=>'استبدال العلم الافتراضي','Re-run Setup Wizard'=>'إعادة تشغيل معالج الإعداد','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'يسمح لك معالج الإعداد بإعداد TranslatePress بسرعة. يمكنك تشغيله في أي وقت.','Language Settings'=>'إعدادات اللغة','Use Native language name'=>'استخدام الاسم الأصلي للغة','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'حدد هذا الخيار إذا كنت تريد عرض اللغات بأسمائها الأصلية. وإلا، فستُعرض اللغات بالإنجليزية.','Use a subdirectory for the default language'=>'استخدام مجلد فرعي للغة الافتراضية','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'حدد هذا الخيار إذا كنت تريد إضافة المجلد الفرعي في عنوان URL للغة الافتراضية.</br>عند تحديد هذا الخيار، ستصبح اللغة الافتراضية التي يراها زوار الموقع هي الأولى في قائمة "كل اللغات".','Force language in custom links'=>'فرض اللغة في الروابط المخصصة','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'اختر "نعم" إذا كنت تريد فرض الروابط المخصصة بدون ترميز اللغة للحفاظ على اللغة المحددة حالياً.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'استخدم shortcode في أي صفحة أو عنصر واجهة.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'يمكنك أيضًا إضافة <a href="%s" title="توثيق مكوّن مبدّل اللغة">مكوّن مبدّل اللغة</a> في محرّر Gutenberg لـ WP.','Menu item'=>'عنصر القائمة','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'انتقل إلى  %1$s المظهر -> القوائم%2$s لإضافة لغات إلى مبدّل اللغة في أي قائمة.','Learn more in our documentation.'=>'تعرّف على المزيد في توثيقنا.','Floating language selection'=>'اختيار اللغة العائم','Add a floating dropdown that follows the user on every page.'=>'أضف قائمة منسدلة عائمة تتبع المستخدم في كل صفحة.','Show "Powered by TranslatePress"'=>'إظهار "مدعوم بواسطة TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'إظهار التسمية الصغيرة "مدعوم بواسطة TranslatePress" في مبدّل اللغة العائم.','5 Days to Better Multilingual Websites'=>'5 أيام لمواقع متعددة اللغات أفضل','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sانضم إلى دورة التأهيل المجانية والحصرية%s وتعلّم كيف تنمّي حركة مرورك متعددة اللغات، وتصل إلى الأسواق الدولية، وتوفّر الوقت والمال مع الاستفادة القصوى من TranslatePress!','Invalid email address'=>'عنوان بريد إلكتروني غير صالح','Your email'=>'بريدك الإلكتروني','Sign me up!'=>'سجّلني!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'سجّل باستخدام عنوان بريدك الإلكتروني واحصل على دليل بريدي من 5 أجزاء لمساعدتك على الاستفادة القصوى من TranslatePress.','Dismiss email course notification'=>'تجاهل إشعار دورة البريد الإلكتروني','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'مرحبًا %s،<br>لا تفوّت أي تحديث مهم - اشترك في إشعارات تحديثات الأمان والميزات، وفي التتبع التشخيصي غير الحسّاس.','Allow & Continue'=>'السماح والمتابعة','Skip'=>'تخطّي','This will allow TranslatePress to:'=>'سيسمح هذا لـ TranslatePress بما يلي:','Your profile overview'=>'نظرة عامة على ملفك الشخصي','Name and email address'=>'الاسم وعنوان البريد الإلكتروني','Admin Notices'=>'إشعارات المسؤول','Updates, announcements, marketing, no spam'=>'التحديثات، والإعلانات، والتسويق، دون رسائل مزعجة','Plugin status & settings'=>'حالة الإضافة والإعدادات','Active, Deactivated, installed version and settings'=>'نشطة، معطلة، النسخة المثبتة والإعدادات','Privacy Policy'=>'سياسة الخصوصية','Terms of Service'=>'شروط الخدمة','Support'=>'الدعم','Documentation'=>'التوثيق','Add Extra AI Words'=>'إضافة كلمات ذكاء اصطناعي إضافية','Optimize TranslatePress database tables'=>'تحسين جداول قاعدة بيانات TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>ملاحظة هامة:</strong> قبل تنفيذ هذا الإجراء، يُنصح بشدة بأخذ نسخة احتياطية من قاعدة البيانات أولاً.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'هام: يُنصح بشدة بأخذ نسخة احتياطية من قاعدة البيانات أولاً!! هل أنت متأكد أنك تريد المتابعة؟','Operations to perform'=>'العمليات المراد تنفيذها','Remove CDATA for original and dictionary strings'=>'إزالة CDATA للسلاسل الأصلية وسلاسل القاموس','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'يزيل CDATA من جداول trp_original_strings وtrp_dictionary_*.<br>يجب ألا يكتشف TranslatePress هذا النوع من المحتوى. ربما تم إدخاله في قاعدة البيانات في إصدارات أقدم من الإضافة.','Remove untranslated links from dictionary tables'=>'إزالة الروابط غير المترجمة من جداول القاموس','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'يزيل الروابط والصور غير المترجمة من جميع جداول trp_dictionary_*. تحتوي هذه الجداول على ترجمات للسلاسل التي أدخلها المستخدم مثل محتوى المقال، وعنوان المقال، والقوائم وغيرها.','Remove duplicate rows for gettext strings'=>'إزالة الصفوف المكررة لسلاسل Gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'تنظيف جميع جداول trp_gettext_* من الصفوف المكررة. تحتوي هذه الجداول على ترجمات لسلاسل القوالب والإضافات.','Remove duplicate rows for dictionary strings'=>'إزالة الصفوف المكررة لسلاسل القاموس','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'تنظيف جميع جداول trp_dictionary_* من الصفوف المكررة. تحتوي هذه الجداول على ترجمات للسلاسل التي أدخلها المستخدم مثل محتوى المقال، وعنوان المقال، والقوائم وغيرها.','Remove duplicate rows for original dictionary strings'=>'إزالة الصفوف المكررة للسلاسل الأصلية في القاموس','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'تنظيف جدول trp_original_strings من الصفوف المكررة. يحتوي هذا الجدول على السلاسل باللغة الافتراضية دون أي ترجمة.<br>يتم أيضًا إعادة إنشاء جدول trp_original_meta، الذي يحتوي على معلومات تعريف تشير إلى معرّف أصل المقال.<br>يمكن أن تظهر هذه التكرارات في حالات استثنائية ناتجة عن سلوك غير متوقع.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'استبدال سلاسل gettext التي يكون معرّفها الأصلي NULL بالمعرّفات الأصلية الصحيحة','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'يُصلح مشكلة حالة حدية حيث يكون معرّف بعض سلاسل gettext الأصلي مُعيّنًا بشكل غير صحيح على NULL، مما يتسبب في مشاكل في محرر الترجمة.<br>تصحح هذه العملية المعرّفات الأصلية في جداول trp_gettext_*.<br>حدد هذا الخيار فقط إذا واجهت مشكلة في محرر الترجمة عندما لم يؤدي النقر على القلم الأخضر إلى إظهار سلسلة gettext للترجمة في الشريط الجانبي الأيسر.<br>وإلا، يُرجى ترك هذا الخيار غير محدد لأنها عملية مكثفة.','Optimize Database'=>'تحسين قاعدة البيانات','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'جاري تحديث جداول TranslatePress. يُرجى إبقاء هذه النافذة مفتوحة.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'ستظل اللغات غير النشطة مرئية ونشطة للمسؤول. بالنسبة للمستخدمين الآخرين، لن تكون مرئية في مبدّلات اللغة ولن تكون متاحة أيضًا.','unknown'=>'غير معروف','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'يتطلب <strong>Extra Languages add-on</strong> إصدار TranslatePress %1$s أو أحدث. أنت تستخدم حاليًا الإصدار %2$s. يُرجى تحديث TranslatePress لتفعيل هذه الميزة.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'تمت إزالة تغييرات الترجمة التلقائية واليدوية لـ slug التي أُجريت عندما كان <strong>TranslatePress - Multilingual</strong> 2.8.4 نشطًا، بسبب بعض المشاكل في ذلك الإصدار. جميع ترجمات slug من قبل ذلك الإصدار قيد الاستخدام الآن. شكرًا لتفهمك!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'إذا كنت بحاجة إليها بشكل مطلق، يمكن العثور على الترجمات المُزالة في جداول trp_slug_original_obsolete وtrp_slug_translation_obsolete.','View Docs'=>'عرض المستندات','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'تعيين نطاقات أو نطاقات فرعية مختلفة لكل لغة. عندما يصل الزائرون إلى هذه النطاقات، يُحمّل TranslatePress ترجمة اللغة المناسبة مباشرة دون إعادة توجيه.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'مثال: %1$s للإنجليزية، و%2$s للإسبانية، و%3$s للفرنسية.','Before enabling:'=>'قبل التفعيل:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'تأكد من تسجيل نطاقاتك وتوجيهها إلى خادمك وتكوين شهادات SSL.','Domain'=>'النطاق','Map this language to a different domain or sub-domain.'=>'اربط هذه اللغة بنطاق مختلف أو نطاق فرعي.','https://example.com'=>'https://example.com','Prefill with current domain'=>'التعبئة المسبقة بالنطاق الحالي','Check DNS'=>'التحقق من DNS','Checking DNS...'=>'جاري التحقق من DNS...','DNS is correctly configured!'=>'تم تكوين DNS بشكل صحيح!','DNS check failed. Please verify your domain configuration.'=>'فشل التحقق من DNS. يُرجى التحقق من تكوين نطاقك.','This domain is already assigned to another language.'=>'هذا النطاق مُخصص بالفعل للغة أخرى.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>إضافة نطاق مختلف لكل لغة</strong> تتطلب إصدار TranslatePress %1$s أو أعلى. أنت تستخدم حاليًا الإصدار %2$s. يُرجى تحديث TranslatePress لتفعيل هذه الميزة.','Note: This option is disabled when Different Domain for Language addon is active.'=>'ملاحظة: هذا الخيار مُعطل عندما تكون إضافة نطاق مختلف للغة نشطة.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'نطاق مختلف لكل لغة: النطاق مطلوب عند تمكين ربط النطاقات. تم تعطيل المفتاح للغات ذات النطاقات الفارغة.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'نطاق مختلف لكل لغة: لا يمكن تخصيص نفس النطاق لعدة لغات. تم تعطيل المفتاح للنطاقات المكررة.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'نطاق مختلف لكل لغة: لا يمكن أن يكون نطاق اللغة مطابقًا لعنوان URL الرئيسي للموقع. تم تعطيل المفتاح للنطاق المطابق.','Please enter a domain.'=>'يُرجى إدخال نطاق.','Invalid domain format.'=>'تنسيق النطاق غير صالح.','Could not reach domain: %s'=>'تعذر الوصول إلى النطاق: %s','Domain returned HTTP status %d.'=>'أعاد النطاق حالة HTTP %d.','Domain is reachable!'=>'النطاق قابل للوصول!','Limit this menu item to the following languages'=>'اقتصر عنصر القائمة هذا على اللغات التالية','Date format'=>'تنسيق التاريخ','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'خصّص تنسيق التاريخ لكل لغة مترجمة.<br/>اتركه فارغًا لاستخدام الإعداد الافتراضي لـ WP أو اطّلع على مزيد من المعلومات <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">هنا</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'لتحرير لغة TranslatePress موجودة، أدخل رمز اللغة واملأ الأعمدة التي تريد استبدالها فقط (مثل اسم اللغة، العلم).<br>يمكنك أيضًا إضافة لغات مخصصة جديدة. ستكون متاحة ضمن الإعدادات العامة، قائمة جميع اللغات، حيث يمكن تحرير slug URL.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'للعلم المخصص، ارفع الصورة أولاً إلى مكتبة الوسائط ثم الصق URL.<br>سيؤثر تغيير لغة مخصصة أو حذفها على الترجمات وعناوين URL الخاصة بالموقع.<br>يجب أن يحتوي رمز اللغة ورمز ISO على أحرف وأرقام فقط، و"-" و"_".<br>يمكن العثور على رموز ISO على <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">رموز ISO من Google</a> و<a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">رموز الهدف من DeepL</a>.','Language code'=>'رمز اللغة','Language name'=>'اسم اللغة','Native name'=>'الاسم الأصلي','ISO Code'=>'رمز ISO','Flag URL'=>'URL العلم','Text RTL'=>'نص من اليمين إلى اليسار','Custom language'=>'لغة مخصصة','Disable dynamic translation'=>'تعطيل الترجمة الديناميكية','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'يعطل اكتشاف السلاسل المعروضة ديناميكيًا باستخدام JavaScript. <br/>ستظل السلاسل المحمّلة عبر استدعاء AJAX من جانب الخادم تُترجم.','Disable translation for gettext strings'=>'تعطيل الترجمة لسلاسل gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'سلاسل Gettext هي سلاسل تُخرجها القوالب والإضافات. <br> قد يكون ترجمة هذه الأنواع من السلاسل عبر TranslatePress غير ضروري إذا كانت قد تمت ترجمتها بالفعل باستخدام نظام ملفات الترجمة .po/.mo.<br>يمكن أن يؤدي تمكين هذا الخيار إلى تحسين أداء تحميل الصفحة في موقعك في حالات معينة. العيب أنك لن تتمكن بعد ذلك من تحرير ترجمات Gettext باستخدام TranslatePress، ولا من الاستفادة من الترجمة التلقائية لهذه السلاسل.','Gettext Strings translation is disabled'=>'ترجمة سلاسل Gettext معطلة','To enable it go to '=>'لتمكينها، انتقل إلى ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->الإعدادات المتقدمة->تصحيح الأخطاء->تعطيل الترجمة لسلاسل Gettext',' and uncheck the Checkbox.'=>' وألغِ تحديد مربع الاختيار.','Dismiss'=>'تجاهل','Exclude translated links from sitemap'=>'استبعاد الروابط المترجمة من sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'لا تُدرج الروابط المترجمة في sitemaps التي تُنشئها إضافات SEO.<br/>يتطلب تثبيت وتفعيل <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> إضافة SEO Pack</a>.','Disable post container tags for post title'=>'تعطيل وسوم حاوية المنشور لعنوان المنشور','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'يعطل فهرسة بحث عنوان المنشور في اللغات المترجمة.<br/>مفيد عندما لا يسمح عنوان المنشور بـ HTML مما يُسبب تعطّل الصفحة.','Disable post container tags for post content'=>'تعطيل وسوم حاوية المنشور لمحتوى المنشور','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'يعطل فهرسة بحث محتوى المنشور في اللغات المترجمة.<br/>مفيد عندما لا يسمح محتوى المنشور بـ HTML مما يُسبب تعطّل الصفحة.','Do not translate certain paths'=>'عدم ترجمة مسارات معينة','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'اختر المسارات التي يمكن ترجمتها. يدعم استخدام wildcard في نهاية المسار.<br>على سبيل المثال، لاستبعاد https://example.com/some/path يمكنك إما استخدام القاعدة /some/path/ أو /some/*.<br>أدخل كل قاعدة في سطرها الخاص. لاستبعاد الصفحة الرئيسية استخدم {home}.','Exclude Paths From Translation'=>'استبعاد المسارات من الترجمة','Translate Only Certain Paths'=>'ترجمة مسارات معينة فقط','Enable the hreflang x-default tag for language:'=>'تمكين وسم hreflang x-default للغة:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'يمكّن وسم hreflang="x-default" للغة بأكملها. راجع التوثيق لمزيد من التفاصيل.','Translate numbers and numerals'=>'ترجمة الأرقام والأعداد','Enable translation of numbers ( e.g. phone numbers)'=>'تمكين ترجمة الأرقام ( مثل أرقام الهاتف)','Selector'=>'المحدد','Exclude from dynamic translation'=>'استبعاد من الترجمة الديناميكية','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'عدم ترجمة السلاسل ديناميكيًا التي تُوجد في عُقَد HTML المطابقة لهذه المحددات.<br>يستثني جميع العناصر الفرعية لعُقَد HTML المطابقة لهذه المحددات من الترجمة باستخدام JavaScript.<br/>ستظل هذه السلاسل تُترجم على جانب الخادم إذا أمكن.','Gettext String'=>'سلسلة Gettext','Exclude Gettext Strings'=>'استبعاد سلاسل Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'استبعاد هذه السلاسل من الترجمة كسلاسل Gettext بواسطة TranslatePress. اترك النطاق فارغًا ليتم تطبيقه على أي سلسلة Gettext.<br/>لا تزال قابلة للترجمة عبر ملفات po/mo.','Exclude selectors only from automatic translation'=>'استبعد المحددات من الترجمة الآلية فقط','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'عدم ترجمة السلاسل تلقائيًا التي تُوجد في عُقَد HTML المطابقة لهذه المحددات.<br>يستثني جميع العناصر الفرعية لعُقَد HTML المطابقة لهذه المحددات من الترجمة التلقائية.<br>الترجمة اليدوية لهذه السلاسل لا تزال ممكنة.','Exclude selectors from translation'=>'استبعد المحددات من الترجمة','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'عدم ترجمة السلاسل التي تُوجد في عُقَد HTML المطابقة لهذه المحددات.<br>يستثني جميع العناصر الفرعية لعُقَد HTML المطابقة لهذه المحددات من الترجمة.<br>لا يمكن ترجمة هذه السلاسل يدويًا ولا تلقائيًا.','String'=>'سلسلة','Exclude strings from automatic translation'=>'استبعاد السلاسل من الترجمة التلقائية','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'عدم ترجمة هذه السلاسل تلقائيًا (مثال: أسماء، مصطلحات تقنية...)<br>ستُترجم الفقرات التي تحتوي على هذه السلاسل باستثناء الجزء المحدد.','Fix broken HTML'=>'إصلاح HTML التالف','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'محاولة عامة لإصلاح HTML التالف أو المفقود في الصفحات المترجمة.<br/>','Force slash at end of home url:'=>'فرض شرطة مائلة في نهاية عنوان URL الرئيسي:','Ads a slash at the end of the home_url() function'=>'يضيف شرطة مائلة في نهاية دالة home_url()','Show Both (recommended)'=>'عرض كليهما (موصى به)','Remove Country Locale'=>'إزالة الإعدادات المحلية للدولة','Remove Region Independent Locale'=>'إزالة الإعدادات المحلية المستقلة عن المنطقة','Remove duplicate hreflang'=>'إزالة hreflang المكرر','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'اختر أيّ وسوم hreflang ستظهر على موقعك.<br/>نوصي بعرض كلا النوعين من وسوم hreflang كما هو موضح في <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">توثيق Google</a>.<br/>إنّ إزالة الإعدادات المحلية للبلد عند وجود إعدادات محلية متعددة للبلد بنفس اللغة (مثلاً: الإنجليزية البريطانية والإنجليزية الأمريكية) سينتج عنه عرض وسم hreflang واحد مع رابط إلى إحدى الإعدادات المحلية للمنطقة لتلك اللغة فقط.','Default (example: en-US, fr-CA, etc.)'=>'الافتراضي (مثال: en-US، fr-CA، إلخ.)','Regional (example: en, fr, es, etc.)'=>'إقليمي (مثال: en، fr، es، إلخ.)','HTML Lang Attribute Format'=>'تنسيق سمة اللغة في HTML','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'تغيير سمة lang الخاصة بوسم html إلى تنسيق يتضمن بلد/منطقة أو لا. <br>في HTML، يجب استخدام سمة lang (<html lang="en-US">) لتحديد لغة محتوى النص حتى يتمكن المتصفح من عرض محتواك أو معالجته بشكل صحيح (على سبيل المثال، من أجل الوصل، والتنسيق، والتدقيق الإملائي، وما إلى ذلك).','Load legacy Language Switcher'=>'تحميل مبدّل اللغة القديم','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'ينطبق على جميع أنواع مبدّلات اللغة (العائم، وshortcode، والقائمة). عند التفعيل، سيعود الموقع إلى استخدام مبدّل اللغة الأصلي المُعدّ في تبويب الإعدادات العامة، ليحلّ محل النسخة الجديدة القابلة للتخصيص. ستبقى إعدادات مبدّل اللغة الحالية محفوظة، لكن سيتم تجاهلها طالما هذا الخيار مفعّل.','Load legacy SEO Pack Add-On'=>'تحميل إضافة SEO Pack القديمة','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'في حال كان الترحيل الأخير إلى إعادة كتابة slug الجديدة يسبب مشاكل، اضبط هذا على نعم لاستخدام الطريقة القديمة <br> يُرجى <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">فتح تذكرة دعم</a> لإبلاغنا بالمشكلات التي تواجهها.','Manual Translation Only'=>'الترجمة اليدوية فقط','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'يقوم TranslatePress بمسح السلاسل وحفظها في قاعدة البيانات بشكل استباقي عندما يصل المستخدمون إلى الصفحات المترجمة. <br>يعطل هذا الإعداد هذه الوظيفة ويسمح بالترجمة وحفظ السلاسل فقط داخل محرر الترجمة. <br>يعطل أيضًا الترجمة الآلية خارج محرر الترجمة، مما يمنحك تحكمًا أفضل في إنفاق الأحرف، عن طريق ترجمة الصفحات التي تزورها في محرر الترجمة فقط.','Open language switcher only on click'=>'فتح مبدّل اللغة بالنقر فقط','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'افتح مبدّل اللغة shortcode بالنقر عليه بدلاً من التمرير فوقه.<br> أغلقه بالنقر عليه، أو في أي مكان آخر على الشاشة، أو بالضغط على مفتاح Escape. سيؤثر هذا على مبدّل اللغة shortcode فقط.','Show opposite language in the language switcher'=>'عرض اللغة المعاكسة في مبدّل اللغة','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'يحوّل مبدّل اللغة إلى زر يعرض اللغة المتاحة الأخرى، وليس الحالية.<br> يعمل فقط عندما تكون هناك لغتان بالضبط، اللغة الافتراضية ولغة الترجمة.<br>سيؤثر هذا على مبدّل اللغة shortcode ومبدّل اللغة العائم أيضًا.<br> لتحقيق ذلك في مبدّل اللغة في القائمة، انتقل إلى المظهر->قوائم->مبدّل اللغة واختر اللغة المعاكسة.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">انقر هنا</a> للوصول إلى أداة تحسين قاعدة البيانات.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'تساعد في إزالة الترجمات المكررة المحتملة، ومسح البيانات غير الضرورية، وإصلاح مشكلات البيانات الوصفية المحتملة.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">هنا</a> يمكنك مراقبة آخر 5 أخطاء SQL المتعلقة بـ TranslatePress إن وُجدت.','Troubleshooting'=>'استكشاف الأخطاء وإصلاحها','Exclude Gettext strings'=>'استبعاد سلاسل Gettext','Debug'=>'تصحيح الأخطاء','Custom languages'=>'لغات مخصصة','Miscellaneous options'=>'خيارات متنوعة','Exclude strings & pages'=>'استبعاد السلاسل والصفحات','Automatic Translation Memory'=>'ذاكرة الترجمة التلقائية','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'تقديم نفس الترجمة للنص المشابه. يجب أن تحتوي النصوص على نسبة تشابه 95%.<br>يساعد على منع فقدان الترجمة الموجودة عند تصحيح الأخطاء الإملائية أو إجراء تعديلات طفيفة على النص الأصلي. <br>إذا كانت ترجمة موجودة بالفعل لنص أصلي مشابه جدًا، فسيتم استخدامها تلقائيًا للنص الأصلي الحالي.<br>لا يعمل عند إجراء تغييرات على نص يكون جزءًا من كتلة ترجمة ما لم يتم دمج النص الجديد يدويًا مرة أخرى في كتلة ترجمة.<br>يجب أن يحتوي كل نص على 50 حرفًا كحد أدنى.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'تحذير: قد تؤثر هذه الميزة سلبًا في أوقات تحميل الصفحة باللغات الثانوية، وخاصةً مع قواعد البيانات الكبيرة (على سبيل المثال المواقع التي تحتوي على الكثير من الصفحات أو المنتجات). إذا واجهت أوقات تحميل بطيئة، عطّل هذا وحاول مرة أخرى.','Fix missing dynamic content'=>'إصلاح المحتوى الديناميكي المفقود','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'قد يساعد في إصلاح المحتوى المفقود الذي تم إدراجه باستخدام JavaScript. <br> يعرض المحتوى المُدرج ديناميكيًا باللغة الأصلية لحظة قبل انتهاء طلب الترجمة.','Filter Gettext wrapping from post content and title'=>'تصفية تغليف Gettext من محتوى المقالة وعنوانها','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'تُصفّي تغليف Gettext مثل #!trpst#trp-gettext من محتوى وعنوان جميع المقالات المحدّثة. لا يؤثر على محتوى المقالات السابقة. <br/><strong>يُنصح بعمل نسخة احتياطية من قاعدة البيانات قبل التفعيل.</strong>','Filter Gettext wrapping from post meta'=>'تصفية تغليف Gettext من بيانات تعريف المقالة','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'تُصفّي تغليف Gettext مثل #!trpst#trp-gettext من بيانات تعريف جميع المقالات المحدّثة. لا يؤثر على بيانات تعريف المقالات السابقة. <br/><strong>يُنصح بعمل نسخة احتياطية من قاعدة البيانات قبل التفعيل.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'مفتاح Google Translate API','Add your API Key here...'=>'أضف مفتاح API هنا...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'قم بزيارة <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">هذا الرابط</a> لمعرفة كيفية إعداد مفتاح API، و<strong>التحكم في تكاليف API</strong>، وتعيين قيود مرجع HTTP.','Your HTTP referrer is: %s'=>'مرجع HTTP الخاص بك هو: %s','There was an error on the server processing your Google Translate key.'=>'حدث خطأ في الخادم أثناء معالجة مفتاح Google Translate الخاص بك.','There was an error with your Google Translate key.'=>'حدث خطأ في مفتاح Google Translate الخاص بك.','Please check your TranslatePress license key.'=>'يُرجى التحقق من مفتاح ترخيص TranslatePress الخاص بك.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'لم يتم اكتشاف ترخيص نشط لهذا الموقع.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'لتمكين الترجمة التلقائية باستخدام TranslatePress AI، أنت بحاجة إلى مفتاح ترخيص عن طريق إنشاء حساب مجاني.','Create your Free Account'=>'أنشئ حسابك المجاني',' or '=>' أو ','Enter your license key'=>'أدخل مفتاح الترخيص',' Or %1$spurchase one here%2$s'=>' أو %1$sاشترِ واحدًا من هنا%2$s','Your free account includes: '=>'يتضمن حسابك المجاني: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'احصل على المزيد من كلمات الذكاء الاصطناعي وافتح جميع ميزات الذكاء الاصطناعي مع TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'لديك <strong>ترخيص</strong> %s صالح.',' words remaining. '=>' كلمات متبقية. ','Recheck'=>'إعادة التحقق','Rechecking...'=>'جارٍ إعادة التحقق...','Done.'=>'تم.','Manage your license & quota on the %s'=>'أدر ترخيصك وحصتك على %s','TranslatePress.com Account Page'=>'صفحة حساب TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'دعم SEO لـ slug الصفحة وعنوانها والوصف ومعلومات الرسم الاجتماعي لفيسبوك وتويتر. يتم ضبط سمة HTML lang بشكل صحيح.','Enable Modules'=>'تفعيل الوحدات','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'فعّل وحدات الإضافات لتوسيع TranslatePress وتعزيز وظائف موقعك المترجم.','More functionality with TranslatePress Pro.'=>'المزيد من الوظائف مع TranslatePress Pro.','Already a Pro User?'=>'هل أنت مستخدم Pro بالفعل؟','Activate License Key'=>'تفعيل مفتاح الترخيص','This add-on is not available on your current plan.'=>'هذه الإضافة غير متوفرة في خطتك الحالية.','Continue'=>'متابعة','The link you followed has expired. Please reload the page and try again.'=>'انتهت صلاحية الرابط الذي اتبعته. يُرجى إعادة تحميل الصفحة والمحاولة مرة أخرى.','A valid license is required to enable Automatic Translation.'=>'يلزم ترخيص صالح لتفعيل الترجمة التلقائية.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'مفتاح الترخيص معطّل لهذا URL. أعِد تفعيله من <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> إدارة المواقع.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>عدم تطابق مفتاح الترخيص.</strong> مفتاح الترخيص الذي أدخلته لا يتوافق مع إصدار TranslatePress المثبّت لديك.</p><p>يُرجى التحقق من تثبيتك للإصدار الصحيح لترخيصك من حساب TranslatePress الخاص بك.</p>','Automatically translate your website using TranslatePress AI.'=>'ترجمة موقعك تلقائيًا باستخدام TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'لتفعيل الترجمة التلقائية باستخدام TranslatePress AI، يُرجى إدخال مفتاح الترخيص من','your account.'=>'حسابك.','Skip and continue with manual translation »'=>'تخطّ والمتابعة بالترجمة اليدوية »','Get Your Free TranslatePress AI License'=>'احصل على ترخيص TranslatePress AI المجاني','Generate License'=>'توليد الترخيص','Creating a free account includes: '=>'يتضمن إنشاء حساب مجاني: ','Are you a TranslatePress PRO user?'=>'هل أنت مستخدم TranslatePress PRO؟','Install & Activate your pro plugin.'=>'ثبّت & فعّل الإضافة الاحترافية الخاصة بك.','Skip this step'=>'تخطّ هذه الخطوة','The email address you added is incorrect.'=>'عنوان البريد الإلكتروني الذي أدخلته غير صحيح.','Setup Complete'=>'اكتمل الإعداد','You\'re ready to start translating!'=>'أنت جاهز للبدء بالترجمة!','You have successfully set up TranslatePress for your website.'=>'تم إعداد TranslatePress لموقعك بنجاح.','Receive '=>'استلم ','Yes, send me multilingual growth tips.'=>'نعم، أرسل لي نصائح النمو متعدد اللغات.','Start translating'=>'ابدأ الترجمة','Sign Up and Start translating'=>'سجّل وابدأ الترجمة','Please upload a TranslatePress Pro plugin file.'=>'يُرجى رفع ملف إضافة TranslatePress Pro.','Upload error: '=>'خطأ في الرفع: ','Install failed: '=>'فشل التثبيت: ','Plugin installed, but entry file not found. '=>'تم تثبيت الإضافة، لكن لم يُعثر على ملف الإدخال. ','Activation error: '=>'خطأ في التفعيل: ','Invalid plugin specified.'=>'الإضافة المحددة غير صالحة.','Invalid action specified.'=>'الإجراء المحدد غير صالح.','Plugin deactivation failed.'=>'فشل إلغاء تفعيل الإضافة.','Plugin activation failed: '=>'فشل تفعيل الإضافة: ','First, install and activate TranslatePress Pro'=>'أولاً، ثبّت وفعّل TranslatePress Pro','Please upload the TranslatePress PRO zip archive from your'=>'يُرجى رفع أرشيف TranslatePress PRO المضغوط من','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'ثبّت وفعّل','Installed Pro versions'=>'النسخ Pro المثبّتة','« Go back'=>'« رجوع','Activate License »'=>'تفعيل الترخيص »','You are trying to add an invalid additional language. Please select a valid option.'=>'تحاول إضافة لغة إضافية غير صالحة. يُرجى اختيار خيار صالح.','Please add an additional language.'=>'يُرجى إضافة لغة إضافية.','You are trying to add an invalid default language. Please select a valid option.'=>'أنت تحاول إضافة لغة افتراضية غير صالحة. يُرجى اختيار خيار صالح.','You need to select a default language.'=>'يجب عليك تحديد لغة افتراضية.','Configure Site Languages'=>'تهيئة لغات الموقع','Select the default and additional languages for your website.'=>'حدد اللغة الافتراضية واللغات الإضافية لموقعك.','You can edit your site languages at any point.'=>'يمكنك تعديل لغات موقعك في أي وقت.','Additional Language'=>'لغة إضافية','Choose a secondary language...'=>'اختر لغة ثانوية...','Add Language'=>'إضافة لغة','Choose a language...'=>'اختر لغة...','Add more than two languages with TranslatePress Pro.'=>'أضف أكثر من لغتين باستخدام TranslatePress Pro.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'مفتاح الترخيص الخاص بك معطّل لهذا URL. أعِد تمكينه من <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> إدارة المواقع.','Add your License Key'=>'أضف مفتاح الترخيص الخاص بك','Add your License Key to unlock all premium features. Find the License Key in your'=>'أضف مفتاح الترخيص الخاص بك لإلغاء قفل جميع الميزات المتميزة. ابحث عن مفتاح الترخيص في','Your license is valid and active.'=>'ترخيصك صالح ونشط.','« Go Back'=>'« رجوع','Set up Language Switcher'=>'إعداد مبدّل اللغة','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'حدد نمط مبدّل اللغة. ستجد المزيد من طرق عرضه في إعدادات الإضافة.','Displays a small language drop-down across your website, in a corner of your choosing.'=>'يعرض قائمة لغة منسدلة صغيرة عبر موقعك، في زاوية من اختيارك.','Switcher Location'=>'موقع مبدّل اللغة','Apply a Template'=>'تطبيق قالب','You can customize the design later'=>'يمكنك تخصيص التصميم لاحقًا','Default Template'=>'القالب الافتراضي','Dark Template'=>'قالب داكن','Border Template'=>'قالب بحدود','Border'=>'حدود','Transparent Template'=>'قالب شفاف','Transparent'=>'شفاف','Welcome to TranslatePress'=>'مرحبًا بك في TranslatePress','Quick guided setup to configure TranslatePress in no time!'=>'إعداد موجّه سريع لتكوين TranslatePress في وقت قصير!','It takes less than a minute.'=>'تستغرق أقل من دقيقة.','Scanning item %1$d of %2$d...'=>'جارٍ مسح العنصر %1$d من %2$d...','Manually translated'=>'مترجم يدويًا','Automatically translated'=>'مترجم تلقائيًا','Not translated'=>'غير مترجم','Bulk Actions'=>'الإجراءات المجمعة','Delete entries'=>'حذف المدخلات','Edit'=>'تحرير','Delete'=>'حذف','Filter'=>'تصفية','Clear filters'=>'مسح عوامل التصفية','Add New'=>'إضافة جديد','Rescan plugins and theme for strings'=>'إعادة فحص الإضافات والقالب بحثًا عن النصوص','Scanning plugins and theme for strings...'=>'جارٍ فحص الإضافات والقالب بحثًا عن النصوص...','Plugins and theme scan is complete'=>'اكتمل فحص الإضافات والقالب','Plugins and theme scan did not finish due to an error'=>'لم يكتمل فحص الإضافات والقالب بسبب خطأ','Import / Export'=>'استيراد / تصدير','items'=>'عناصر','See More'=>'عرض المزيد','See Less'=>'عرض أقل','Apply'=>'تطبيق','No strings match your query.'=>'لا توجد نصوص تطابق استعلامك.','Try to rescan plugins and theme for strings.'=>'حاول إعادة فحص الإضافات والقالب بحثًا عن النصوص.','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'حدث خطأ أثناء تحميل النتائج. على الأرجح تم تسجيل خروجك. هل تريد إعادة تحميل الصفحة؟','found in translation'=>'موجود في الترجمة','Select All'=>'تحديد الكل','Select Visible'=>'تحديد المرئي','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'أنت على وشك تنفيذ هذا الإجراء على جميع النصوص المطابقة للفلتر، وليس فقط التي تم تحديدها بشكل مرئي. لتنفيذ الإجراء على النصوص المرئية فقط، انقر على "تحديد المرئي" من القائمة المنسدلة لترويسة الجدول.','You are about to perform this action only on the visible strings. To perform the action on all the strings matching the filter click "Select All" from the table header dropdown.'=>'أنت على وشك تنفيذ هذا الإجراء على النصوص المرئية فقط. لتنفيذ الإجراء على جميع النصوص المطابقة للفلتر، انقر على "تحديد الكل" من القائمة المنسدلة لترويسة الجدول.','To continue please type the word:'=>'للمتابعة، يُرجى كتابة الكلمة:','The word typed was incorrect. Action was cancelled.'=>'الكلمة المُدخلة غير صحيحة. تم إلغاء الإجراء.','Warning: This action cannot be undone. Deleting a string will remove its current translation. The original string will appear again in this interface after TranslatePress detects it. This action is NOT equivalent to excluding the string from being translated again.'=>'تحذير: لا يمكن التراجع عن هذا الإجراء. سيؤدي حذف نص إلى إزالة ترجمته الحالية. سيظهر النص الأصلي مرة أخرى في هذه الواجهة بعد أن يكتشفه TranslatePress. هذا الإجراء لا يعادل استبعاد النص من الترجمة مجددًا.','%d original entries and their translations were deleted.'=>'تم حذف %d من الإدخالات الأصلية وترجماتها.','Navigate to next page'=>'الانتقال إلى الصفحة التالية','Navigate to previous page'=>'الانتقال إلى الصفحة السابقة','Navigate to first page'=>'الانتقال إلى الصفحة الأولى','Navigate to last page'=>'الانتقال إلى الصفحة الأخيرة','Type a page number to navigate to'=>'اكتب رقم صفحة للانتقال إليها','Incorrect page number. Type a page number between 1 and total number of pages'=>'رقم الصفحة غير صحيح. اكتب رقم صفحة بين 1 وإجمالي عدد الصفحات','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'ابحث في النصوص الأصلية والمترجمة التي تحتوي على الكلمات المفتاحية المُدخلة مع مطابقة الفلاتر المحددة. ضع النص بين علامتي اقتباس للحصول على تطابق تام: "نص"','Filter strings according to selected translation status, filters and keywords and selected filters'=>'تصفية النصوص وفقًا لحالة الترجمة المحددة والفلاتر والكلمات المفتاحية والفلاتر المحددة','Removes selected filters'=>'إزالة الفلاتر المحددة','See options for selecting all strings'=>'اطلع على خيارات تحديد جميع النصوص','Click to sort strings by this column'=>'انقر لفرز النصوص حسب هذا العمود','Language in which the translation status filter applies. Leave unselected for the translation status to apply to ANY language'=>'اللغة التي تنطبق عليها فلتر حالة الترجمة. اتركه غير محدد لتطبيق حالة الترجمة على أي لغة.','Search'=>'بحث','Slugs that are not found in either one of the other categories.'=>'عناوين slug التي لا توجد في أي من الفئات الأخرى.','Plugins and Theme String Translation'=>'ترجمة نصوص الإضافات والقالب','Gettext'=>'Gettext','Search Gettext Strings'=>'البحث في نصوص Gettext','ID'=>'المعرف','Original String'=>'النص الأصلي','Translation'=>'الترجمة','Filter by domain'=>'تصفية حسب النطاق','Filter by type'=>'تصفية حسب النوع','Email text'=>'نص البريد الإلكتروني','Emails String Translation'=>'ترجمة نصوص البريد الإلكتروني','Emails'=>'البريد الإلكتروني','Search Email Strings'=>'البحث في نصوص البريد الإلكتروني','User Inputted String Translation'=>'ترجمة النصوص المُدخلة من المستخدم','Regular'=>'عادي','Search Regular Strings'=>'البحث في النصوص العادية','Filter by Translation Block'=>'تصفية حسب كتلة الترجمة','URL Slugs Translation'=>'ترجمة slugs الـ URL','String Translation Editor'=>'محرر ترجمة النصوص','TranslatePress has detected and cleaned up some failed translation entries in your database following %1$san isolated incident%2$s. No further action is required.'=>'عثر TranslatePress على بعض إدخالات الترجمة الفاشلة في قاعدة بياناتك وأزالها إثر %1$sحادث معزول%2$s. لا يلزم اتخاذ أي إجراء إضافي.','Post Slug'=>'slug المقال','Invalid language code'=>'رمز لغة غير صالح','First by browser language, then IP address (recommended)'=>'أولاً حسب لغة المتصفح، ثم عنوان IP (موصى به)','First by IP address, then by browser language'=>'أولاً حسب عنوان IP، ثم حسب لغة المتصفح','Only by browser language'=>'حسب لغة المتصفح فقط','Only by IP address'=>'حسب عنوان IP فقط','A popup appears asking the user if they want to be redirected'=>'تظهر نافذة منبثقة تسأل المستخدم إذا كان يريد إعادة التوجيه','Redirect directly (*not recommended)'=>'إعادة التوجيه مباشرة (*غير موصى به)','Pop-up window over the content'=>'نافذة منبثقة فوق المحتوى','Hello bar before the content'=>'شريط ترحيبي قبل المحتوى','WARNING. Cannot determine your language preference based on your current IP.<br>This is most likely because the website is on a local environment.'=>'تحذير. لا يمكن تحديد تفضيل لغتك بناءً على عنوان IP الحالي.<br>على الأرجح لأن الموقع يعمل في بيئة محلية.','Go to <a href="%s" target="_self">Advanced</a> tab to change this feature\'s settings'=>'انتقل إلى تبويب <a href="%s" target="_self">متقدمة</a> لتغيير إعدادات هذه الميزة','User Language Detection Method'=>'طريقة كشف لغة المستخدم','Select how the language should be detected for first time visitors.<br>The visitor\'s last displayed language will be remembered through cookies.'=>'حدد كيفية كشف اللغة للزوار لأول مرة.<br>سيتم تذكر آخر لغة عُرضت للزائر عبر ملفات تعريف الارتباط.','User Notification Popup'=>'نافذة إشعار المستخدم المنبثقة','A popup appears asking the user if they want to be redirected.'=>'تظهر نافذة منبثقة تسأل المستخدم إذا كان يريد إعادة التوجيه.','Popup Type'=>'نوع النافذة المنبثقة','Popup Text'=>'نص النافذة المنبثقة','The same text is displayed in all languages. <br>A selecting language switcher will be appended to the pop-up. The detected language is pre-selected.'=>'يُعرض نفس النص بجميع اللغات. <br>سيتم إلحاق محوّل اختيار اللغة بالنافذة المنبثقة. اللغة المكتشفة محددة مسبقاً.','Button Text'=>'نص الزر','Write the text you wish to appear on the button..'=>'اكتب النص الذي تريد أن يظهر على الزر..','Close Button Text'=>'نص زر الإغلاق','Write the text you wish to appear on the close button. Leave empty for just the close button.'=>'اكتب النص الذي تريد أن يظهر على زر الإغلاق. اتركه فارغاً ليظهر زر الإغلاق فقط.','Bad request. There was an error accessing the DeepL API.'=>'طلب غير صالح. حدث خطأ أثناء الوصول إلى DeepL API.','The API key entered is invalid.'=>'مفتاح API المُدخل غير صالح.','The API resource could not be found.'=>'تعذر العثور على مورد API.','The request size is too large.'=>'حجم الطلب كبير جدًا.','The request is too long.'=>'الطلب طويل جدًا.','Too many requests. Please try again later.'=>'طلبات كثيرة جدًا. يُرجى المحاولة مرة أخرى لاحقًا.','Your translation quota has been reached.'=>'تم استنفاء حصة الترجمة الخاصة بك.','We could not process your request. Please try again later.'=>'تعذر علينا معالجة طلبك. يُرجى المحاولة مرة أخرى لاحقًا.','There is an error on the DeepL service and your request could not be processed.'=>'هناك خطأ في خدمة DeepL وتعذر معالجة طلبك.','DeepL API Type'=>'نوع API لـDeepL','Pro'=>'احترافي','Free'=>'مجاني','Select the type of DeepL API you want to use.'=>'حدد نوع A